// ============================================================
// NOEUD 2 — Recevoir le job_id + Initialiser
// ============================================================

const input = $input.first().json;

const job_id = input.job_id || input.payload?.job_id;
const correlation_id = input.correlation_id || '';
const message_id = input.message_id || null;

if (!job_id) {
  throw new Error('AdaptationAgent — Champ obligatoire manquant: job_id');
}

return [{
  json: {
    tenant_id: input.tenant_id || 1,
    job_id,
    correlation_id,
    incoming_message_id: message_id,
    started_at: new Date().toISOString()
  }
}];

const data = $input.first().json;
return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
    agent: 'ADAPTATION_AGENT',
    event_type: 'ADAPTATION_STARTED',
    message: `Adaptation démarrée pour ${data.job_id}`,
    job_id: data.job_id,
    correlation_id: data.correlation_id
  }
}];

// ============================================================
// Extraire le DiffusionJob + préparer UPDATE → ADAPTING
// ============================================================

const jobResult = $input.first().json;
const initData = $('Recevoir job_id').first().json;

if (!jobResult.success || !jobResult.job) {
  throw new Error(`AdaptationAgent — Job ${initData.job_id} introuvable`);
}

const job = jobResult.job;

let payload = job.payload;
if (typeof payload === 'string') {
  try { payload = JSON.parse(payload); } catch(e) {
    throw new Error(`AdaptationAgent — Payload JSON invalide pour ${job.job_id}`);
  }
}

return [{
  json: {
    ...initData,
    job,
    payload,
    channel_name: job.channel_name,
    diffusion_type: job.diffusion_type,
    funnel_stage: job.funnel_stage,
    action: 'UPDATE_JOB', tenant_id: $('Recevoir job_id').first().json.tenant_id,
    job_id: job.job_id,
    fields: { status: 'ADAPTING' }
  }
}];

// ============================================================
// Validation pré-LLM (UC-02 §5.1 + §5.2)
// ============================================================

const prev = $('Extraire Job + Prép ADAPTING').first().json;
const payload = prev.payload;
const ch = prev.channel_name;
const dt = prev.diffusion_type;

function reject(code, msg) {
  return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
    ...prev,
    _pre_llm_valid: false,
    _result_status: 'REJECTED_PAYLOAD',
    _error_code: code,
    _error_message: msg
  }}];
}

if (!payload || !payload.content || typeof payload.content !== 'object') {
  return reject('REJECTED_PAYLOAD_STRUCTURE', 'payload.content absent ou invalide');
}

const content = payload.content;

if (typeof content.text !== 'string') {
  return reject('REJECTED_PAYLOAD_STRUCTURE', 'content.text absent ou non-string');
}

if (ch === 'INSTAGRAM') {
  if (!content.media || !Array.isArray(content.media) || content.media.length === 0) {
    return reject('MISSING_MEDIA_REQUIRED', 'Média obligatoire pour Instagram');
  }
  if (content.media.filter(m => m && m.url).length === 0) {
    return reject('INVALID_MEDIA', 'Aucun média valide pour Instagram');
  }
}

if (ch === 'FACEBOOK' && dt === 'PAID') {
  if (!content.text || content.text.trim() === '') return reject('MISSING_TEXT_REQUIRED', 'Texte obligatoire pour Facebook PAID');
  if (!content.media || content.media.length === 0) return reject('MISSING_MEDIA_REQUIRED', 'Média obligatoire pour Facebook PAID');
}

if (ch === 'LINKEDIN' && (!content.text || content.text.trim() === '')) {
  return reject('MISSING_TEXT_REQUIRED', 'Texte obligatoire pour LinkedIn');
}

if (!payload.platform_params || typeof payload.platform_params !== 'object') {
  return reject('REJECTED_PAYLOAD_STRUCTURE', 'platform_params absent');
}

if (dt === 'PAID' && (!payload.ads || typeof payload.ads !== 'object')) {
  return reject('REJECTED_PAYLOAD_STRUCTURE', 'Bloc ads absent pour diffusion PAID');
}

return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id,  ...prev, _pre_llm_valid: true } }];

const prev = $('Validation pré-LLM').first().json;
return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
  action: 'GET_CONFIG_BY_CHANNEL',
  channel_name: prev.channel_name,
  diffusion_type: prev.diffusion_type
}}];

// ============================================================
// Construire le prompt LLM (UC-02 §7)
// ============================================================

const configResult = $input.first().json;
const prev = $('Validation pré-LLM').first().json;
const job = prev.job;
const payload = prev.payload;
const content = payload.content;

const config = configResult.configs?.[0] || configResult.config || {};
const text_max = config.text_max_chars || 5000;
const headline_max = config.headline_max_chars || null;
const desc_max = config.description_max_chars || null;
const hashtags_rec = config.hashtags_recommended || 0;
const tone = config.tone_default || 'professionnel';

const FUNNEL_MAP = {
  'TOFU': { ton: 'informatif et accrocheur', objectif: 'attirer l\'attention', cta: 'Découvrez, Saviez-vous que' },
  'MOFU': { ton: 'évaluatif et engageant', objectif: 'renforcer l\'intérêt', cta: 'Comparez, Témoignage client' },
  'BOFU': { ton: 'persuasif et urgent', objectif: 'convertir et pousser à l\'achat', cta: 'Achetez maintenant, Offre limitée' }
};
const funnel = FUNNEL_MAP[prev.funnel_stage] || FUNNEL_MAP['TOFU'];

let constraints = `- Texte principal : ${text_max} caractères maximum`;
if (headline_max) constraints += `\n- Headline : ${headline_max} caractères maximum`;
if (desc_max) constraints += `\n- Description : ${desc_max} caractères maximum`;
constraints += hashtags_rec > 0
  ? `\n- Hashtags : exactement ${hashtags_rec} hashtags pertinents`
  : `\n- Hashtags : aucun (déconseillé pour ce format)`;

let channelRules = '';
if (prev.channel_name === 'INSTAGRAM') channelRules = '- Pas de lien cliquable. Texte visuel et accrocheur.';
else if (prev.channel_name === 'FACEBOOK' && prev.diffusion_type === 'PAID') channelRules = '- PAS de hashtags. Headline et description obligatoires. CTA fort.';
else if (prev.channel_name === 'LINKEDIN') channelRules = '- Ton professionnel. Emojis limités.';

const currentContent = JSON.stringify({
  text: content.text, headline: content.headline || null,
  hashtags: content.hashtags || null, description: content.description || null
}, null, 2);

const systemPrompt = `Tu es un expert en marketing digital spécialisé dans l'adaptation de contenu pour les réseaux sociaux.
Tu adaptes le contenu existant sans créer de contenu original.
Tu retournes UNIQUEMENT un objet JSON valide, sans markdown, sans backticks, sans commentaires.`;

const userPrompt = `## Contexte
- Canal : ${prev.channel_name} | Type : ${prev.diffusion_type} | Funnel : ${prev.funnel_stage}
- Ton : ${funnel.ton} (${tone}) | Objectif : ${funnel.objectif}

## Contraintes techniques
${constraints}
${channelRules ? '\n## Règles canal\n' + channelRules : ''}

## Contenu à adapter
${currentContent}

## Format de sortie (JSON strict)
{ "text": "...", "headline": "..." ou null, "hashtags": ["#tag"] ou null, "description": "..." ou null }

Règles : respecte les limites de caractères. Si headline non requis → null. Si hashtags=0 → null.`;

return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
    ...prev,
    _config: config,
    _system_prompt: systemPrompt,
    _user_prompt: userPrompt,
    _text_max: text_max,
    _headline_max: headline_max,
    _desc_max: desc_max,
    _hashtags_rec: hashtags_rec
  }
}];

const data = $input.first().json;
return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
    agent: 'ADAPTATION_AGENT',
    event_type: 'PROMPT_BUILT',
    message: `Prompt construit, canal ${data.channel_name}, funnel ${data.funnel_stage}`,
    job_id: data.job_id,
    correlation_id: data.correlation_id
  }
}];

// Passer le prompt au nœud AI Agent
const data = $('Construire Prompt LLM').first().json;
return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id,  ...data } }];

// ============================================================

// Validation post-LLM (UC-02 §5.3)

// ============================================================



const aiResult = $input.first().json;

const promptData = $('Construire Prompt LLM').first().json;

const prev = promptData;

const startTime = Date.now();



// --- 1. Extraire la réponse de l'AI Agent ---

let llmText = aiResult.output || aiResult.text || aiResult.response || '';



if (!llmText || llmText.trim() === '') {

  return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 

    ...prev,

    _post_llm_valid: false,

    _result_status: 'FAILED_LLM',

    _error_code: 'LLM_EMPTY_RESPONSE',

    _error_message: 'Le LLM a retourné une réponse vide'

  }}];

}



// --- 2. Parser le JSON ---

let adapted;

try {

  let cleaned = llmText.trim();

  if (cleaned.startsWith('```json')) cleaned = cleaned.slice(7);

  if (cleaned.startsWith('```')) cleaned = cleaned.slice(3);

  if (cleaned.endsWith('```')) cleaned = cleaned.slice(0, -3);

  adapted = JSON.parse(cleaned.trim());

} catch(e) {

  return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 

    ...prev,

    _post_llm_valid: false,

    _result_status: 'FAILED_ADAPTATION',

    _error_code: 'LLM_INVALID_JSON',

    _error_message: `Sortie LLM non-JSON: ${llmText.substring(0, 200)}`

  }}];

}



// --- 3. Vérifier la structure ---

if (typeof adapted.text !== 'string' || adapted.text.trim() === '') {

  return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 

    ...prev,

    _post_llm_valid: false,

    _result_status: 'FAILED_ADAPTATION',

    _error_code: 'LLM_MISSING_TEXT',

    _error_message: 'Champ text absent ou vide'

  }}];

}



// --- 4. Contraintes de longueur ---

if (adapted.text.length > prev._text_max) {

  return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 

    ...prev,

    _post_llm_valid: false,

    _result_status: 'FAILED_ADAPTATION',

    _error_code: 'TEXT_TOO_LONG',

    _error_message: `text: ${adapted.text.length} car. > max ${prev._text_max}`

  }}];

}



if (prev._headline_max && adapted.headline && adapted.headline.length > prev._headline_max) {

  return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 

    ...prev,

    _post_llm_valid: false,

    _result_status: 'FAILED_ADAPTATION',

    _error_code: 'HEADLINE_TOO_LONG',

    _error_message: `headline: ${adapted.headline.length} car. > max ${prev._headline_max}`

  }}];

}



if (prev._desc_max && adapted.description && adapted.description.length > prev._desc_max) {

  return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 

    ...prev,

    _post_llm_valid: false,

    _result_status: 'FAILED_ADAPTATION',

    _error_code: 'DESCRIPTION_TOO_LONG',

    _error_message: `description: ${adapted.description.length} car. > max ${prev._desc_max}`

  }}];

}



// --- 5. Hashtags ---

if (adapted.hashtags && Array.isArray(adapted.hashtags) && prev._hashtags_rec === 0) {

  adapted.hashtags = null;

}



return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 

  ...prev,

  _post_llm_valid: true,

  _adapted_content: adapted,

  _processing_time_ms: Date.now() - startTime,

  _llm_raw: llmText.substring(0, 500)

}}];

// ============================================================
// Assembler payload adapté (UC-02 §6 étape 8)
// content adapté (LLM) + media/link/platform_params/ads inchangés
// ============================================================

const data = $input.first().json;
const originalPayload = data.payload;
const adaptedContent = data._adapted_content;
const originalContent = originalPayload.content;

const newContent = {
  text: adaptedContent.text,
  headline: adaptedContent.headline || null,
  media: originalContent.media || [],
  link: originalContent.link || null,
  hashtags: adaptedContent.hashtags || null,
  description: adaptedContent.description || null
};

if (originalContent.link && adaptedContent.display_text) {
  newContent.link = { ...originalContent.link, display_text: adaptedContent.display_text };
}

const adaptedPayload = {
  content: newContent,
  platform_params: originalPayload.platform_params,
  ...(originalPayload.ads ? { ads: originalPayload.ads } : {})
};

return [{ json: {
  ...data,
  _adapted_payload: adaptedPayload,
  action: 'UPDATE_JOB', tenant_id: $('Recevoir job_id').first().json.tenant_id,
  job_id: data.job_id,
  fields: {
    status: 'ADAPTED',
    payload: JSON.stringify(adaptedPayload)
  }
}}];

const data = $('Assembler payload adapté').first().json;
return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
    agent: 'ADAPTATION_AGENT',
    event_type: 'ADAPTATION_COMPLETED',
    message: `Payload adapté et persisté pour ${data.job_id}, statut=ADAPTED`,
    job_id: data.job_id,
    correlation_id: data.correlation_id
  }
}];

const data = $('Assembler payload adapté').first().json;
return [{ json: {
  status: 'SUCCESS',
  source: 'ADAPTATION_AGENT',
  target: 'ORCHESTRATOR',
  correlation_id: data.correlation_id,
  in_reply_to: data.incoming_message_id,
  payload: {
    tenant_id: data.tenant_id,
    job_id: data.job_id,
    channel_name: data.channel_name,
    result_status: 'ADAPTED',
    processing_time_ms: data._processing_time_ms || 0
  }
}}];

// Convergence ÉCHEC : REJECTED_PAYLOAD / FAILED_LLM / FAILED_ADAPTATION
const data = $input.first().json;
return [{ json: {
  ...data,
  action: 'UPDATE_JOB', tenant_id: $('Recevoir job_id').first().json.tenant_id,
  job_id: data.job_id,
  fields: {
    status: data._result_status || 'FAILED_ADAPTATION',
    last_error: JSON.stringify({ error_code: data._error_code, error_message: data._error_message })
  }
}}];

const data = $('Préparer UPDATE échec').first().json;
return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
    agent: 'ADAPTATION_AGENT',
    event_type: data._result_status || 'ADAPTATION_FAILURE',
    message: `${data._result_status}: ${data._error_message} pour ${data.job_id}`,
    job_id: data.job_id,
    correlation_id: data.correlation_id
  }
}];

const data = $('Préparer UPDATE échec').first().json;
return [{ json: {
  status: 'SUCCESS',
  source: 'ADAPTATION_AGENT',
  target: 'ORCHESTRATOR',
  correlation_id: data.correlation_id,
  in_reply_to: data.incoming_message_id,
  payload: {
    tenant_id: data.tenant_id,
    job_id: data.job_id,
    result_status: data._result_status,
    error_code: data._error_code,
    error_message: data._error_message
  }
}}];
